from itertools import product
vars = ['a','b','c','y']
# generate all 3-clauses with repetition allowed, order canonical nondecreasing by literal index
lits=[]
for v in vars:
    lits.append((v,1))
    lits.append((v,0))
clauses=[]
for i in range(len(lits)):
  for j in range(i,len(lits)):
    for k in range(j,len(lits)):
      clauses.append((lits[i],lits[j],lits[k]))
print('num clauses',len(clauses))

def eval_clause(cl, asn):
    return int(any(asn[v] if pos else not asn[v] for v,pos in cl))

# precompute signatures: best satisfiable count over y for each abc pattern
sigs=[]
for cl in clauses:
    sig=[]
    for abc in product([0,1],[0,1],[0,1]):
        base={'a':abc[0],'b':abc[1],'c':abc[2]}
        best=max(eval_clause(cl, base|{'y':yy}) for yy in [0,1])
        sig.append(best)
    sigs.append(tuple(sig))

# search q=2..4 using combinations with replacement? brute force nested loops acceptable
for q in [2,4,6]:
    print('search q',q)
    # recursive over indices nondecreasing
    found=False
    def rec(start, depth, cur):
        nonlocal found
        if found: return
        if depth==q:
            totals=[0]*8
            for idx in cur:
                sig=sigs[idx]
                totals=[t+s for t,s in zip(totals,sig)]
            true_vals=[totals[i] for i in range(1,8)]
            false_val=totals[0]
            if len(set(true_vals))==1:
                a=true_vals[0]; b=false_val
                if a*2==q and b==a-1:
                    print('FOUND',q,a,b,[clauses[i] for i in cur])
                    found=True
            return
        for i in range(start,len(clauses)):
            rec(i, depth+1, cur+[i])
            if found: return
    rec(0,0,[])
    if found: break
print('done')
